The following changes implement the requested feature to upload/capture an image of a handwritten report.

**Changes:**

1.  **`metadata.json`**: Added `camera` permission.
2.  **`components/InputBar.tsx`**:
    *   Added a small **Camera Button** with a hidden file input.
    *   On mobile, this opens the camera directly (`capture="environment"`). On desktop, it opens the file picker.
    *   Handles image file reading (Base64) and sends it to the AI service.
3.  **`services/geminiService.ts`**:
    *   Added `parseTransactionImage` function.
    *   It sends the image + a specific prompt to Gemini to extract handwritten data, applying the same rules (Entry/Exit classification, "REPASSE SEMID", etc.) as the text input.

# Updated files:

## metadata.json

```json
{
  "name": "Relatório Financeiro IDM",
  "description": "Sistema inteligente para preenchimento de relatórios financeiros da Igreja de Deus Missionária com correção automática de texto via IA.",
  "requestFramePermissions": [
    "camera"
  ]
}
```

## components/InputBar.tsx

```tsx
import React, { useState, useRef } from 'react';
import { Send, Loader2, Sparkles, Camera } from 'lucide-react';
import { TransactionType } from '../types';
import { parseTransactionInput, parseTransactionImage } from '../services/geminiService';

interface InputBarProps {
  onAdd: (data: { day: string; description: string; value: number; type: TransactionType }) => void;
}

export const InputBar: React.FC<InputBarProps> = ({ onAdd }) => {
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const processResults = (results: any[]) => {
    if (results && results.length > 0) {
      results.forEach(item => {
         onAdd(item);
      });
      return true;
    }
    return false;
  };

  const handleSmartAdd = async () => {
    if (!input.trim()) return;
    setIsLoading(true);
    try {
      const results = await parseTransactionInput(input);
      if (processResults(results || [])) {
        setInput('');
      } else {
        alert("Não entendi o lançamento. Tente algo como 'Dia 5 oferta 50' ou separe vários com ponto: 'Dia 5 oferta 50. Dia 6 luz 100.'");
      }
    } catch (e) {
      console.error(e);
      alert("Erro de conexão com a IA.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsLoading(true);

    const reader = new FileReader();
    reader.readAsDataURL(file);

    reader.onload = async () => {
      try {
        const base64Data = reader.result as string;
        // Remove the data URL prefix (e.g., "data:image/jpeg;base64,")
        const base64Content = base64Data.split(',')[1];

        const results = await parseTransactionImage(base64Content, file.type);

        if (processResults(results || [])) {
          alert(`${results?.length} lançamentos identificados e adicionados!`);
        } else {
          alert("Não foi possível ler os dados da imagem. Tente uma foto mais clara e legível.");
        }
      } catch (error) {
        console.error(error);
        alert("Erro ao processar imagem.");
      } finally {
        setIsLoading(false);
        // Reset file input
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };

    reader.onerror = () => {
      setIsLoading(false);
      alert("Erro ao ler arquivo.");
    };
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSmartAdd();
    }
  };

  return (
    <div className="p-4 rounded-xl border border-blue-200 bg-blue-50/50 shadow-sm">
      <div className="flex items-center gap-2 mb-2">
        <Sparkles size={16} className="text-blue-600" />
        <h3 className="font-semibold text-blue-900 text-sm">
          Lançamento Inteligente
        </h3>
        <span className="text-[10px] text-blue-500 ml-auto hidden sm:inline">
          Separe múltiplos com ponto (.) ou use a câmera
        </span>
      </div>

      <div className="flex gap-2 items-end">
        <textarea
          rows={1}
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Digite: 'Dia 10 Dízimo 100'..."
          className="flex-1 p-3 border border-blue-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white text-gray-900 text-base shadow-inner placeholder-gray-400 resize-none overflow-hidden h-[48px]"
          disabled={isLoading}
        />

        {/* Hidden File Input */}
        <input 
          type="file" 
          ref={fileInputRef}
          accept="image/*"
          capture="environment"
          className="hidden"
          onChange={handleImageUpload}
        />

        {/* Camera Button */}
        <button
          onClick={() => fileInputRef.current?.click()}
          disabled={isLoading}
          className="bg-slate-200 hover:bg-slate-300 text-slate-700 w-[48px] h-[48px] rounded-lg font-medium transition-colors flex items-center justify-center shadow-sm disabled:opacity-50"
          title="Tirar foto da folha manuscrita"
        >
          <Camera size={20} />
        </button>

        {/* Send Button */}
        <button
          onClick={handleSmartAdd}
          disabled={isLoading || !input.trim()}
          className="bg-blue-600 hover:bg-blue-700 text-white w-[48px] h-[48px] rounded-lg font-medium transition-colors flex items-center justify-center shadow-sm disabled:opacity-50"
        >
          {isLoading ? <Loader2 className="animate-spin" size={20} /> : <Send size={20} />}
        </button>
      </div>
    </div>
  );
};
```

## services/geminiService.ts

```typescript
import { GoogleGenAI, Type } from "@google/genai";
import { TransactionType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
Você é um tesoureiro experiente da 'Igreja de Deus Missionária'.

REGRA DE NEGÓCIO:
1. Identifique se é ENTRADA ou SAIDA.
    - SAIDA: Compra, Pagamento, Gasto, Retirada, Ajuda, "passar", "pagar", "gas", "luz", "água", "gratificação", "Gratificação", "Oferta pregador", "Oferta missionária", "Ajuda social", "Gratificação do obreiro", "Oferta Obreiro".
    - ENTRADA: Dízimo, Oferta (exceto oferta ao pregador), Voto, Doação, "receber", "Santa Ceia", "Culto de Ceia".
2. Extraia DIA (número), VALOR (número) e DESCRIÇÃO (texto corrigido/formal).
3. Se o texto conter "semid", "cemid" ou similar, a DESCRIÇÃO deve ser: "REPASSE SEMID" (em maiúsculo).
4. Capitalize nomes próprios (ex: "pregadora iara" -> "Pregadora Iara").
5. "luz" -> "Energia Elétrica", "gas" -> "Gás de Cozinha".
6. Se houver "Santa Ceia" ou "Culto de Ceia" como ENTRADA, mantenha a descrição normal. (O sistema gerará a saída automaticamente, não você).

Retorne um JSON Array.
`;

const RESPONSE_SCHEMA = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      day: { type: Type.STRING },
      description: { type: Type.STRING },
      value: { type: Type.NUMBER },
      type: { type: Type.STRING, enum: [TransactionType.ENTRY, TransactionType.EXIT] }
    },
    required: ["description", "value", "type"],
  }
};

export const parseTransactionInput = async (
  inputText: string
): Promise<{ day: string; description: string; value: number; type: TransactionType }[] | null> => {
  if (!inputText.trim()) return null;

  try {
    const prompt = `
      Analise o texto do usuário, que pode conter UM ou MÚLTIPLOS lançamentos separados por PONTO FINAL ".".
      Texto do usuário: "${inputText}"
      Siga rigorosamente as regras de negócio definidas na instrução do sistema.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA,
      },
    });

    if (response.text) {
      return JSON.parse(response.text);
    }
    return null;

  } catch (error) {
    console.error("Gemini Parse Error:", error);
    return null;
  }
};

export const parseTransactionImage = async (
  base64Data: string,
  mimeType: string
): Promise<{ day: string; description: string; value: number; type: TransactionType }[] | null> => {
  try {
    const prompt = `
      Analise esta imagem de um relatório financeiro manuscrito ou impresso.
      Extraia TODOS os lançamentos de linhas visíveis.

      Geralmente o formato é: DIA | DESCRIÇÃO | VALOR (Entrada ou Saída).
      Ignore cabeçalhos e rodapés. Foque apenas nas linhas de transações.
      Siga rigorosamente as regras de negócio para classificar ENTRADA/SAIDA e formatar descrições.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data
            }
          },
          { text: prompt }
        ]
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA,
      },
    });

    if (response.text) {
      return JSON.parse(response.text);
    }
    return null;

  } catch (error) {
    console.error("Gemini Image Parse Error:", error);
    return null;
  }
};

To help you type faster without needing a specialized physical keyboard, I have added a **"Quick Words" (Sugestões Rápidas)** toolbar just above the input field.

**How it works:**
1.  **Common Words**: I included the most frequent terms used in your report (Dia, Dízimo, Oferta, Compra, Pagamento, etc.).
2.  **One-Tap Typing**: Clicking a word automatically inserts it into the text box.
3.  **Smart Spacing**: It automatically adds a space after the word so you can keep typing immediately.

