## App.tsx

Improved `toggleFullScreen` to handle cross-browser compatibility (Safari/iOS) and notify user if not supported.

```tsx
import React, { useState, useEffect, useRef } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, FileText, Maximize, Maximize2, Minimize2 } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.55);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const previewContainerRef = useRef<HTMLDivElement>(null);
  const A4_WIDTH_PX = 794; // Approx width of 210mm at 96dpi

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      const data = JSON.parse(saved);
      setTransactions(data.transactions || []);
      setMonth(data.month || MONTHS[new Date().getMonth()]);
      setYear(data.year || new Date().getFullYear().toString());
      setPreviousBalance(data.previousBalance?.toString() || '0.00');
    }

    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    document.addEventListener('webkitfullscreenchange', handleFullscreenChange); // Safari support

    return () => {
      document.removeEventListener('fullscreenchange', handleFullscreenChange);
      document.removeEventListener('webkitfullscreenchange', handleFullscreenChange);
    };
  }, []);

  useEffect(() => {
    localStorage.setItem('idm_report_data', JSON.stringify({
      transactions,
      month,
      year,
      previousBalance
    }));
  }, [transactions, month, year, previousBalance]);

  // Fit Width Function
  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      // Calculate zoom to fit width minus small padding
      const newZoom = (containerWidth - 20) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.2)); // Prevent it from being too small
    }
  };

  // Initial Auto-Fit
  useEffect(() => {
    // Small timeout to ensure layout is rendered
    setTimeout(handleFitWidth, 100);

    // Add resize listener
    window.addEventListener('resize', handleFitWidth);
    return () => window.removeEventListener('resize', handleFitWidth);
  }, []);

  // Smart Auto-scroll: Centers the view on the last added transaction row
  useEffect(() => {
    if (previewContainerRef.current && transactions.length > 0) {
      setTimeout(() => {
        if (!previewContainerRef.current) return;

        // Approximate pixel calculations for A4 Paper at current zoom
        const HEADER_OFFSET = 260; 
        const ROW_HEIGHT = 24;     

        // Calculate the Y position of the last filled row on the paper
        const targetYOnPaper = HEADER_OFFSET + (transactions.length * ROW_HEIGHT);

        // Convert to zoomed pixels in the container
        const targetPixel = targetYOnPaper * zoom;

        // Center it: Target - (Half Viewport Height)
        const containerHeight = previewContainerRef.current.clientHeight;
        const scrollTo = targetPixel - (containerHeight / 2);

        previewContainerRef.current.scrollTo({
          top: Math.max(0, scrollTo),
          behavior: 'smooth'
        });
      }, 300);
    }
  }, [transactions, zoom]); // Trigger when transaction list changes or zoom changes

  const toggleFullScreen = () => {
    const doc = document as any;
    const docEl = document.documentElement as any;

    if (!doc.fullscreenElement && !doc.webkitFullscreenElement && !doc.mozFullScreenElement && !doc.msFullscreenElement) {
      // Request Fullscreen
      if (docEl.requestFullscreen) {
        docEl.requestFullscreen().catch((err: any) => console.log(err));
      } else if (docEl.webkitRequestFullscreen) { /* Safari */
        docEl.webkitRequestFullscreen();
      } else if (docEl.msRequestFullscreen) { /* IE11 */
        docEl.msRequestFullscreen();
      } else if (docEl.mozRequestFullScreen) { /* Firefox */
        docEl.mozRequestFullScreen();
      } else {
        alert("Seu dispositivo (provavelmente iPhone) não permite tela cheia via botão.\n\nPara usar em tela cheia:\n1. Toque no botão 'Compartilhar' do navegador.\n2. Escolha 'Adicionar à Tela de Início'.");
      }
    } else {
      // Exit Fullscreen
      if (doc.exitFullscreen) {
        doc.exitFullscreen();
      } else if (doc.webkitExitFullscreen) {
        doc.webkitExitFullscreen();
      } else if (doc.mozCancelFullScreen) {
        doc.mozCancelFullScreen();
      } else if (doc.msExitFullscreen) {
        doc.msExitFullscreen();
      }
    }
  };

  const addTransactions = (newTransactions: { day: string; description: string; value: number; type: TransactionType }[]) => {
    setTransactions(prev => {
      let updatedList = [...prev];

      newTransactions.forEach(data => {
        const normalizedDesc = data.description.trim();

        // Check for duplicate/summation
        const existingIndex = updatedList.findIndex(t => 
          t.day === data.day && 
          t.description.toLowerCase() === normalizedDesc.toLowerCase() && 
          t.type === data.type
        );

        if (existingIndex >= 0) {
          updatedList[existingIndex] = {
            ...updatedList[existingIndex],
            value: updatedList[existingIndex].value + data.value
          };
        } else {
          updatedList.push({
            id: uuidv4(),
            day: data.day,
            description: normalizedDesc,
            value: data.value,
            type: data.type
          });
        }

        // --- SYNCHRONOUS AUTO-LOGIC FOR "SANTA CEIA" ---
        if (data.type === TransactionType.ENTRY) {
          const lowerDesc = normalizedDesc.toLowerCase();
          if (lowerDesc.includes("culto de ceia") || lowerDesc.includes("santa ceia")) {
             const autoDesc = "REPASSE SEMID";
             const existingAutoIndex = updatedList.findIndex(t => 
               t.day === data.day && 
               t.description === autoDesc && 
               t.type === TransactionType.EXIT
             );

             if (existingAutoIndex >= 0) {
               updatedList[existingAutoIndex] = {
                 ...updatedList[existingAutoIndex],
                 value: updatedList[existingAutoIndex].value + data.value
               };
             } else {
               updatedList.push({
                 id: uuidv4(),
                 day: data.day,
                 description: autoDesc,
                 value: data.value,
                 type: TransactionType.EXIT
               });
             }
          }
        }
        // -----------------------------------------------
      });

      return updatedList;
    });
  };

  const removeTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions
      .filter(t => t.type === TransactionType.ENTRY)
      .reduce((acc, t) => acc + t.value, 0);

    const dizimoValue = totalEntries * 0.10;

    if (dizimoValue <= 0) {
      alert("Não há entradas suficientes para calcular o dízimo.");
      return;
    }

    const exists = transactions.some(t => t.description.includes("Dízimo da Sede"));
    if (exists && !confirm("Já existe um lançamento de 'Dízimo da Sede'. Deseja adicionar outro?")) {
      return;
    }

    addTransactions([{
      day: new Date().getDate().toString().padStart(2, '0'),
      description: "Dízimo da Sede (10%)",
      value: parseFloat(dizimoValue.toFixed(2)),
      type: TransactionType.EXIT
    }]);
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');

    // @ts-ignore
    if (typeof window.html2pdf !== 'undefined' && element) {
       setIsGeneratingPdf(true);

       const opt = {
         margin: 0,
         filename: `Relatorio_Financeiro_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       };

       // @ts-ignore
       window.html2pdf()
         .set(opt)
         .from(element)
         .save()
         .then(() => {
            setIsGeneratingPdf(false);
         })
         .catch((err: any) => {
            console.error(err);
            setIsGeneratingPdf(false);
            alert("Erro ao gerar PDF. Tentando método alternativo...");
            window.print();
         });
    } else {
       window.print();
    }
  };

  const clearAll = () => {
    if (confirm("Tem certeza que deseja limpar todo o relatório?")) {
      setTransactions([]);
    }
  };

  const adjustZoom = (delta: number) => {
    setZoom(prev => {
      const newZoom = prev + delta;
      return Math.min(Math.max(newZoom, 0.2), 2.5);
    });
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row font-sans overflow-hidden bg-gray-900">

      {/* SIDEBAR - CONTROLS (Top 75% on Mobile) */}
      <div className="w-full lg:w-96 bg-slate-800 text-white flex flex-col h-[75%] lg:h-full shadow-xl z-20 border-r border-slate-700">

        {/* Header */}
        <div className="p-3 bg-slate-900 border-b border-slate-700 flex items-center justify-between shrink-0">
          <h2 className="text-base font-bold flex items-center gap-2 text-yellow-500">
            <Calculator size={18} /> 
            Financeiro IDM
          </h2>
          <button 
            onClick={toggleFullScreen}
            className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 rounded-lg text-slate-300 hover:text-white transition-colors border border-slate-600 text-xs font-medium"
          >
            {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
            <span className="hidden sm:inline">{isFullscreen ? 'Sair' : 'Tela Cheia'}</span>
          </button>
        </div>

        {/* Scrollable Content Area */}
        <div className="flex-1 overflow-y-auto p-3 space-y-3 custom-scrollbar">

          {/* Config Section */}
          <div className="bg-slate-700 p-2 rounded-lg space-y-2">
            <div className="flex gap-2">
              <div className="flex-1">
                <label className="block text-[10px] uppercase text-slate-400 mb-1">Mês</label>
                <select 
                  value={month} 
                  onChange={e => setMonth(e.target.value)}
                  className="w-full bg-slate-900 border border-slate-600 rounded p-1 text-sm focus:border-yellow-500 outline-none"
                >
                  {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                </select>
              </div>
              <div className="w-20">
                <label className="block text-[10px] uppercase text-slate-400 mb-1">Ano</label>
                <input 
                  type="text" 
                  value={year}
                  onChange={e => setYear(e.target.value)}
                  className="w-full bg-slate-900 border border-slate-600 rounded p-1 text-sm focus:border-yellow-500 outline-none"
                />
              </div>
            </div>
            <div>
              <label className="block text-[10px] uppercase text-slate-400 mb-1">Saldo Anterior (R$)</label>
              <input 
                type="number" 
                step="0.01"
                value={previousBalance}
                onChange={e => setPreviousBalance(e.target.value)}
                className="w-full bg-slate-900 border border-slate-600 rounded p-1 text-sm focus:border-yellow-500 outline-none font-mono"
              />
            </div>
          </div>

          {/* Unified Input Bar */}
          <InputBar onAdd={(item) => addTransactions([item])} />

          {/* Quick Actions */}
          <div className="grid grid-cols-1 gap-2">
             <button 
              onClick={calculateDizimoSede}
              className="flex items-center justify-center gap-1 bg-purple-600/20 hover:bg-purple-600/40 text-purple-300 border border-purple-600/30 p-2 rounded text-xs transition-colors"
             >
               <Calculator size={14} /> Calcular e Adicionar Dízimo Sede (10%)
             </button>
          </div>

          {/* Transaction List (Moved to Sidebar) */}
          <div className="bg-slate-700 rounded-lg overflow-hidden flex flex-col min-h-0">
             <div className="bg-slate-900/50 p-2 px-3 border-b border-slate-600 flex justify-between items-center shrink-0">
                <h3 className="font-semibold text-xs uppercase tracking-wider text-slate-300 flex items-center gap-1">
                  <FileText size={12}/> Lançamentos ({transactions.length})
                </h3>
                {transactions.length > 0 && (
                   <button onClick={clearAll} className="text-red-400 hover:text-red-300 text-[10px] uppercase flex items-center gap-1">
                     <Trash2 size={10} /> Limpar
                   </button>
                )}
             </div>
             <div className="flex-1 overflow-y-auto p-1 custom-scrollbar min-h-[120px]">
                {transactions.length === 0 ? (
                  <p className="text-slate-500 text-xs text-center py-4">Nenhum lançamento.</p>
                ) : (
                  <ul className="space-y-1">
                    {transactions.slice().reverse().map(t => (
                      <li key={t.id} className="group flex justify-between items-center text-xs bg-slate-800 p-2 rounded border border-slate-600/50 hover:border-slate-500 transition-colors">
                        <div className="flex-1 overflow-hidden">
                           <span className={`font-mono font-bold mr-2 ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>
                             Dia {t.day}
                           </span>
                           <span className="text-slate-300 truncate block">{t.description}</span>
                        </div>
                        <div className="flex flex-col items-end gap-1 ml-2">
                           <span className="font-bold text-slate-200">
                             {t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                           </span>
                           <button onClick={() => removeTransaction(t.id)} className="text-slate-500 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity">
                             <Trash2 size={14} />
                           </button>
                        </div>
                      </li>
                    ))}
                  </ul>
                )}
             </div>
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-3 bg-slate-900 border-t border-slate-700 shrink-0">
           <button 
            onClick={handleDownloadPDF}
            disabled={isGeneratingPdf}
            className="w-full flex items-center justify-center gap-2 bg-yellow-500 hover:bg-yellow-600 text-slate-900 font-bold p-2.5 rounded transition-colors text-sm disabled:opacity-50"
           >
             {isGeneratingPdf ? 'GERANDO...' : (
               <>
                 <Download size={18} /> BAIXAR PDF
               </>
             )}
           </button>
        </div>
      </div>

      {/* MAIN CONTENT - PREVIEW AREA (Bottom 25% on Mobile) */}
      <div className="flex-1 h-[25%] lg:h-full bg-gray-200 relative flex flex-col overflow-hidden border-t-4 border-gray-900 lg:border-t-0">

        {/* Toolbar */}
        <div className="h-8 bg-white border-b border-gray-300 flex items-center justify-between px-3 shadow-sm z-10 no-print shrink-0">
            <span className="text-[10px] font-semibold uppercase text-gray-500 tracking-wider">Visualização</span>
            <div className="flex items-center gap-1 bg-gray-100 rounded-lg p-0.5">
                <button 
                  onClick={handleFitWidth}
                  className="p-1 hover:bg-white rounded shadow-sm text-blue-600"
                  title="Ajustar à Largura"
