                  <ZoomOut size={12}/>
                </button>
                <span className="text-[10px] font-mono w-8 text-center text-gray-700 select-none">
                  {Math.round(zoom * 100)}%
                </span>
                <button 
                  onClick={() => adjustZoom(0.1)}
                  className="p-1 hover:bg-white rounded shadow-sm text-gray-600"
                  title="Aumentar Zoom"
                >
                  <ZoomIn size={12}/>
                </button>
            </div>
        </div>

        {/* Canvas */}
        <div 
          ref={previewContainerRef}
          className="flex-1 overflow-auto p-2 flex justify-center bg-gray-300/50 relative custom-scrollbar"
        >
           <div 
             className="origin-top transition-transform duration-200 ease-out shadow-2xl bg-white"
