               marginBottom: '100px'
             }}
           >
              <div id="report-content">
                <PaperReport 
                  transactions={transactions} 
                  header={{
                    month,
                    year,
                    previousBalance: parseFloat(previousBalance || '0')
                  }} 
                />
              </div>
           </div>
        </div>
      </div>

    </div>
  );
}

export default App;

