import React, { useState, useRef, useEffect } from 'react';
import { Send, Loader2, Sparkles, Camera, Mic, MicOff } from 'lucide-react';
import { TransactionType } from '../types';
import { parseTransactionInput, parseTransactionImage } from '../services/geminiService';

interface InputBarProps {
  onAdd: (data: { day: string; description: string; value: number; type: TransactionType }) => void;
  onVoiceCommand?: (command: string, args?: any) => void;
  isListening?: boolean;
  onToggleVoice: () => void;
}

export const InputBar: React.FC<InputBarProps> = ({ onAdd, onToggleVoice, isListening }) => {
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isFocused, setIsFocused] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const processResults = (results: any[]) => {
    if (results && results.length > 0) {
      results.forEach(item => {
         onAdd(item);
      });
      return true;
    }
    return false;
  };

  const handleSmartAdd = async () => {
    if (!input.trim()) return;
    setIsLoading(true);
    try {
      const results = await parseTransactionInput(input);
      if (processResults(results || [])) {
        setInput('');
        textareaRef.current?.blur();
      } else {
        alert("Não entendi o lançamento. Tente algo como 'Dia 5 oferta 50'");
      }
    } catch (e) {
      console.error(e);
      alert("Erro de conexão com a IA.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsLoading(true);
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = async () => {
      try {
        const base64Data = reader.result as string;
        const base64Content = base64Data.split(',')[1];
        const results = await parseTransactionImage(base64Content, file.type);
        if (processResults(results || [])) {
          alert(`${results?.length} lançamentos adicionados!`);
        }
      } catch (error) {
        alert("Erro ao processar imagem.");
      } finally {
        setIsLoading(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSmartAdd();
    }
  };

  return (
    <div className={`p-3 rounded-xl border transition-all duration-300 ${isFocused ? 'border-blue-500 bg-white ring-4 ring-blue-500/10' : 'border-slate-600 bg-slate-800/50'}`}>

      <div className="flex items-center justify-between mb-2">
        <div className="flex items-center gap-2">
            <Sparkles size={14} className={isFocused ? "text-blue-500" : "text-slate-400"} />
            <h3 className={`font-semibold text-[10px] uppercase tracking-wider ${isFocused ? "text-blue-600" : "text-slate-300"}`}>
              {isFocused ? "Modo de Escrita Ampla" : "Lançamento Inteligente"}
            </h3>
        </div>
        {isListening && (
          <div className="flex items-center gap-1">
             <span className="w-2 h-2 bg-red-500 rounded-full animate-pulse"></span>
             <span className="text-[10px] text-red-400 font-bold uppercase">Ouvindo...</span>
          </div>
        )}
      </div>

      <div className="flex gap-2 items-end">
        <textarea
          ref={textareaRef}
          rows={isFocused ? 4 : 1}
          value={input}
          onFocus={() => setIsFocused(true)}
          onBlur={() => {
            if (!input) setIsFocused(false);
          }}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Diga ou digite: 'Dia 10 luz 150.00'..."
          className={`flex-1 p-3 rounded-lg focus:outline-none bg-slate-900 text-white shadow-inner placeholder-slate-500 resize-none transition-all duration-300 ${isFocused ? 'text-lg' : 'text-sm'}`}
          disabled={isLoading}
        />

        <input type="file" ref={fileInputRef} accept="image/*" capture="environment" className="hidden" onChange={handleImageUpload} />

        <div className="flex flex-col gap-1">
          <button
            onClick={onToggleVoice}
            className={`w-10 h-10 rounded-lg flex items-center justify-center transition-all ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-slate-700 text-slate-300 hover:bg-slate-600'}`}
            title="Comando de Voz"
          >
            {isListening ? <Mic size={20} /> : <Mic size={20} />}
          </button>

          <button
            onClick={() => fileInputRef.current?.click()}
            disabled={isLoading}
            className="bg-slate-700 hover:bg-slate-600 text-slate-300 w-10 h-10 rounded-lg flex items-center justify-center transition-colors disabled:opacity-50"
          >
            <Camera size={20} />
          </button>
        </div>

        <button
          onClick={handleSmartAdd}
          disabled={isLoading || !input.trim()}
          className="bg-blue-600 hover:bg-blue-700 text-white w-12 h-21 self-stretch rounded-lg font-medium transition-colors flex items-center justify-center shadow-lg disabled:opacity-50"
        >
          {isLoading ? <Loader2 className="animate-spin" size={20} /> : <Send size={20} />}
        </button>
      </div>

      {isFocused && (
        <div className="mt-2 flex justify-end">
           <button 
             onClick={() => setIsFocused(false)}
             className="text-[10px] text-slate-400 hover:text-white uppercase font-bold"
           >
             Recolher
           </button>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, FileText, Maximize2, Minimize2, Edit3, X, Eye, EyeOff } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.55);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  // Voice State
  const [isListening, setIsListening] = useState(false);
  const sessionRef = useRef<any>(null);

  const previewContainerRef = useRef<HTMLDivElement>(null);
  const A4_WIDTH_PX = 794;

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      const data = JSON.parse(saved);
      setTransactions(data.transactions || []);
      setMonth(data.month || MONTHS[new Date().getMonth()]);
      setYear(data.year || new Date().getFullYear().toString());
      setPreviousBalance(data.previousBalance?.toString() || '0.00');
    }

    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  useEffect(() => {
    localStorage.setItem('idm_report_data', JSON.stringify({ transactions, month, year, previousBalance }));
  }, [transactions, month, year, previousBalance]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.2));
    }
  };

  useEffect(() => {
    setTimeout(handleFitWidth, 200);
    window.addEventListener('resize', handleFitWidth);
    return () => window.removeEventListener('resize', handleFitWidth);
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  // --- BUSINESS LOGIC ---

  const addTransactions = (newItems: any[]) => {
    setTransactions(prev => {
      let updated = [...prev];
      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const existingIndex = updated.findIndex(t => t.day === data.day && t.description.toLowerCase() === normalizedDesc.toLowerCase() && t.type === data.type);
        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
        } else {
          updated.push({ id: uuidv4(), day: data.day, description: normalizedDesc, value: data.value, type: data.type });
        }

        // Auto Repasse SEMID logic
        if (data.type === TransactionType.ENTRY && (normalizedDesc.toLowerCase().includes("ceia"))) {
           const repasse = { id: uuidv4(), day: data.day, description: "REPASSE SEMID", value: data.value, type: TransactionType.EXIT };
           updated.push(repasse);
        }
      });
      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));
    if (value > 0) addTransactions([{ day: new Date().getDate().toString().padStart(2, '0'), description: "Dízimo da Sede (10%)", value, type: TransactionType.EXIT }]);
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  // --- VOICE COMMANDS (LIVE API) ---

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const controlFunctions = [
      {
        name: 'add_entry',
        description: 'Adiciona uma nova transação (entrada ou saída).',
        parameters: {
          type: Type.OBJECT,
          properties: {
            day: { type: Type.STRING },
            description: { type: Type.STRING },
            value: { type: Type.NUMBER },
            type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] }
          },
          required: ['description', 'value', 'type']
        }
      },
      { name: 'delete_last', description: 'Remove o último lançamento feito.' },
      { name: 'download_report', description: 'Gera e baixa o PDF do relatório.' },
      { name: 'calculate_dizimo', description: 'Calcula e adiciona o dízimo da sede de 10%.' },
      { name: 'full_preview', description: 'Entra ou sai do modo de visualização em tela cheia do PDF.' },
      { name: 'set_zoom', description: 'Ajusta o zoom da visualização.', parameters: { type: Type.OBJECT, properties: { level: { type: Type.NUMBER } } } }
    ];

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: controlFunctions }],
          systemInstruction: 'Você é um assistente de tesouraria. Execute comandos no sistema de relatório financeiro da igreja através das funções disponíveis. Se o usuário pedir para adicionar algo, use add_entry. Se pedir para baixar, use download_report. Se pedir para calcular 10%, use calculate_dizimo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor);
            processor.connect(audioContext.destination);
            setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                if (fc.name === 'download_report') handleDownloadPDF();
                if (fc.name === 'calculate_dizimo') calculateDizimoSede();
                if (fc.name === 'full_preview') setIsFullPreview(prev => !prev);
                if (fc.name === 'delete_last') setTransactions(prev => prev.slice(0, -1));
                if (fc.name === 'set_zoom') setZoom(fc.args.level || 0.6);

                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false),
          onerror: () => setIsListening(false)
        }
      });
      sessionRef.current = { stop: () => { audioContext.close(); stream.getTracks().forEach(t => t.stop()); } };
    } catch (e) {
      console.error(e);
      alert("Erro ao acessar microfone.");
    }
  };

  const toggleVoice = () => {
