import React, { useState, useEffect, useRef } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
// Fixed: Added Sparkles and Loader2 to the imports from lucide-react
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, FileText, Maximize2, Minimize2, Edit3, X, Eye, EyeOff, Sparkles, Loader2 } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.55);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  // Voice State
  const [isListening, setIsListening] = useState(false);
  const sessionRef = useRef<any>(null);

  const previewContainerRef = useRef<HTMLDivElement>(null);
  const A4_WIDTH_PX = 794;

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      const data = JSON.parse(saved);
      setTransactions(data.transactions || []);
      setMonth(data.month || MONTHS[new Date().getMonth()]);
      setYear(data.year || new Date().getFullYear().toString());
      setPreviousBalance(data.previousBalance?.toString() || '0.00');
    }

    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  useEffect(() => {
    localStorage.setItem('idm_report_data', JSON.stringify({ transactions, month, year, previousBalance }));
  }, [transactions, month, year, previousBalance]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.2));
    }
  };

  useEffect(() => {
    setTimeout(handleFitWidth, 200);
    window.addEventListener('resize', handleFitWidth);
    return () => window.removeEventListener('resize', handleFitWidth);
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  // --- BUSINESS LOGIC ---

  const addTransactions = (newItems: any[]) => {
    setTransactions(prev => {
      let updated = [...prev];
      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();
        const existingIndex = updated.findIndex(t => t.day === data.day && t.description.toLowerCase() === normalizedDesc.toLowerCase() && t.type === data.type);
        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
        } else {
          updated.push({ id: uuidv4(), day: data.day, description: normalizedDesc, value: data.value, type: data.type });
        }

        // Auto Repasse SEMID logic
        if (data.type === TransactionType.ENTRY && (normalizedDesc.toLowerCase().includes("ceia"))) {
           const repasse = { id: uuidv4(), day: data.day, description: "REPASSE SEMID", value: data.value, type: TransactionType.EXIT };
           updated.push(repasse);
        }
      });
      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));
    if (value > 0) addTransactions([{ day: new Date().getDate().toString().padStart(2, '0'), description: "Dízimo da Sede (10%)", value, type: TransactionType.EXIT }]);
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  // --- VOICE COMMANDS (LIVE API) ---

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const controlFunctions = [
      {
        name: 'add_entry',
        description: 'Adiciona uma nova transação (entrada ou saída).',
        parameters: {
          type: Type.OBJECT,
          properties: {
            day: { type: Type.STRING },
            description: { type: Type.STRING },
            value: { type: Type.NUMBER },
            type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] }
          },
          required: ['description', 'value', 'type']
        }
      },
      { name: 'delete_last', description: 'Remove o último lançamento feito.' },
      { name: 'download_report', description: 'Gera e baixa o PDF do relatório.' },
      { name: 'calculate_dizimo', description: 'Calcula e adiciona o dízimo da sede de 10%.' },
      { name: 'full_preview', description: 'Entra ou sai do modo de visualização em tela cheia do PDF.' },
      { name: 'set_zoom', description: 'Ajusta o zoom da visualização.', parameters: { type: Type.OBJECT, properties: { level: { type: Type.NUMBER } } } }
    ];

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: controlFunctions }],
          systemInstruction: 'Você é um assistente de tesouraria. Execute comandos no sistema de relatório financeiro da igreja através das funções disponíveis. Se o usuário pedir para adicionar algo, use add_entry. Se pedir para baixar, use download_report. Se pedir para calcular 10%, use calculate_dizimo.'
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor);
            processor.connect(audioContext.destination);
            setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                if (fc.name === 'download_report') handleDownloadPDF();
                if (fc.name === 'calculate_dizimo') calculateDizimoSede();
                if (fc.name === 'full_preview') setIsFullPreview(prev => !prev);
                if (fc.name === 'delete_last') setTransactions(prev => prev.slice(0, -1));
                if (fc.name === 'set_zoom') setZoom(fc.args.level || 0.6);

                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false),
          onerror: () => setIsListening(false)
        }
      });
      sessionRef.current = { stop: () => { audioContext.close(); stream.getTracks().forEach(t => t.stop()); } };
    } catch (e) {
      console.error(e);
      alert("Erro ao acessar microfone.");
    }
  };

  const toggleVoice = () => {
    if (isListening) {
      sessionRef.current?.stop();
      setIsListening(false);
    } else {
      startVoiceSession();
    }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden">

      {/* SIDEBAR - Only visible if NOT in full preview */}
      {!isFullPreview && (
        <div className="w-full lg:w-[420px] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">
          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between">
            <h1 className="text-lg font-bold text-yellow-500 flex items-center gap-2">
              <Calculator size={20} /> Financeiro IDM
            </h1>
            <div className="flex gap-2">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400">
                 {isFullscreen ? <Minimize2 size={18} /> : <Maximize2 size={18} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 hover:bg-blue-600/30 rounded-lg lg:hidden" title="Ver PDF">
                 <Eye size={18} />
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
            <div className="grid grid-cols-2 gap-3 bg-slate-800/50 p-3 rounded-xl border border-slate-700">
              <div>
                <label className="text-[10px] uppercase text-slate-500 block mb-1">Período</label>
                <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-900 border border-slate-700 rounded p-1.5 text-xs outline-none focus:border-yellow-500">
                  {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                </select>
              </div>
              <div>
                <label className="text-[10px] uppercase text-slate-500 block mb-1">Ano</label>
                <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-900 border border-slate-700 rounded p-1.5 text-xs outline-none focus:border-yellow-500" />
              </div>
              <div className="col-span-2">
                <label className="text-[10px] uppercase text-slate-500 block mb-1">Saldo Anterior (R$)</label>
                <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-900 border border-slate-700 rounded p-1.5 text-sm font-mono outline-none focus:border-yellow-500" />
              </div>
            </div>

            <InputBar onAdd={(item) => addTransactions([item])} isListening={isListening} onToggleVoice={toggleVoice} />

            <div className="flex flex-col gap-2">
               {/* Fixed: Replaced missing icon reference with the now-imported Sparkles component */}
               <button onClick={calculateDizimoSede} className="w-full py-2 bg-purple-600/10 hover:bg-purple-600/20 text-purple-400 border border-purple-600/30 rounded-lg text-xs font-bold transition-all flex items-center justify-center gap-2">
                 <Sparkles size={14}/> CALCULAR DÍZIMO SEDE (10%)
               </button>
            </div>

            <div className="space-y-2">
              <div className="flex justify-between items-center px-1">
                <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest">Lançamentos Recentes</h3>
                <span className="bg-slate-800 px-2 py-0.5 rounded text-[10px] text-slate-400 font-bold">{transactions.length} itens</span>
              </div>
              <div className="space-y-2">
                {transactions.slice().reverse().map(t => (
                  <div key={t.id} className="group bg-slate-800/40 border border-slate-800 hover:border-slate-600 p-3 rounded-xl flex items-center justify-between transition-all">
                    <div className="flex flex-col">
                      <div className="flex items-center gap-2">
                        <span className={`w-1.5 h-1.5 rounded-full ${t.type === TransactionType.ENTRY ? 'bg-green-500' : 'bg-red-500'}`}></span>
                        <span className="text-[10px] font-bold text-slate-500">DIA {t.day}</span>
                      </div>
                      <span className="text-sm font-medium text-slate-200 uppercase truncate max-w-[180px]">{t.description}</span>
                    </div>
                    <div className="flex flex-col items-end gap-1">
                      <span className={`font-mono font-bold ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>
                        {t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </span>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingTransaction(t)} className="p-1.5 hover:bg-slate-700 rounded text-blue-400"><Edit3 size={14} /></button>
                        <button onClick={() => deleteTransaction(t.id)} className="p-1.5 hover:bg-red-900/40 rounded text-red-500"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800">
            {/* Fixed: Replaced missing icon reference with the now-imported Loader2 component */}
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-3 rounded-xl flex items-center justify-center gap-2 shadow-lg shadow-yellow-500/10 disabled:opacity-50 transition-all uppercase tracking-tight">
              {isGeneratingPdf ? <Loader2 className="animate-spin" /> : <Download size={20} />} BAIXAR RELATÓRIO PDF
            </button>
          </div>
        </div>
      )}

      {/* PREVIEW AREA */}
      <div className={`flex-1 flex flex-col bg-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full' : 'h-[35%] lg:h-full'}`}>

        {/* Full Preview Controls */}
        <div className="absolute top-4 right-4 z-40 flex gap-2 no-print">
           {isFullPreview && (
             <button onClick={() => setIsFullPreview(false)} className="bg-red-600 hover:bg-red-700 text-white px-4 py-2 rounded-full shadow-2xl flex items-center gap-2 font-bold uppercase text-xs">
               <X size={18} /> Sair do Modo Preview
             </button>
           )}
           {!isFullPreview && (
              <button onClick={() => setIsFullPreview(true)} className="hidden lg:flex bg-slate-900/80 backdrop-blur hover:bg-slate-900 text-white p-3 rounded-full shadow-xl items-center gap-2 font-bold uppercase text-xs border border-slate-700">
                <Maximize2 size={18} /> Tela Cheia
              </button>
           )}
        </div>

        <div className="h-10 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-4 shrink-0 no-print">
           <div className="flex items-center gap-2">
             <span className="text-[10px] font-black text-slate-500 tracking-tighter uppercase">Visualizador A4</span>
             {isFullPreview && <span className="bg-blue-500/20 text-blue-400 px-2 py-0.5 rounded text-[10px] font-bold">MODO FOCO</span>}
           </div>
           <div className="flex items-center gap-3 bg-slate-800 rounded-lg p-1">
             <button onClick={() => setZoom(z => Math.max(0.2, z-0.1))} className="p-1 hover:text-white"><ZoomOut size={16}/></button>
             <span className="text-[10px] font-mono w-10 text-center">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.1))} className="p-1 hover:text-white"><ZoomIn size={16}/></button>
             <button onClick={handleFitWidth} className="p-1 ml-1 bg-slate-700 rounded hover:bg-slate-600"><Maximize2 size={12}/></button>
           </div>
        </div>

        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 lg:p-8 flex justify-center bg-slate-800 custom-scrollbar scroll-smooth">
           <div className="origin-top transition-transform duration-300 shadow-[0_35px_60px_-15px_rgba(0,0,0,0.6)]" style={{ transform: `scale(${zoom})` }}>
              <div id="report-content">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} />
              </div>
           </div>
        </div>
      </div>

      {/* EDIT MODAL */}
      {editingTransaction && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-4 bg-slate-800 flex justify-between items-center">
              <h3 className="font-bold flex items-center gap-2"><Edit3 size={18}/> Editar Lançamento</h3>
              <button onClick={() => setEditingTransaction(null)} className="text-slate-400 hover:text-white"><X size={20}/></button>
            </div>
            <div className="p-6 space-y-4">
              <div className="grid grid-cols-4 gap-4">
                <div className="col-span-1">
                  <label className="text-[10px] uppercase font-bold text-slate-500">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded p-2 text-sm outline-none focus:border-blue-500" />
                </div>
                <div className="col-span-3">
                  <label className="text-[10px] uppercase font-bold text-slate-500">Descrição</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded p-2 text-sm outline-none focus:border-blue-500 uppercase" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-[10px] uppercase font-bold text-slate-500">Valor</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded p-2 text-sm outline-none focus:border-blue-500 font-mono" />
                </div>
                <div>
                  <label className="text-[10px] uppercase font-bold text-slate-500">Tipo</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded p-2 text-sm outline-none focus:border-blue-500">
                    <option value={TransactionType.ENTRY}>ENTRADA</option>
                    <option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="pt-4 flex gap-3">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl font-bold transition-all">CANCELAR</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold transition-all shadow-lg shadow-blue-500/20">SALVAR ALTERAÇÕES</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Transaction, TransactionType, MONTHS } from './types';
import { InputBar } from './components/InputBar';
import { PaperReport } from './components/PaperReport';
import { Download, Trash2, Calculator, ZoomIn, ZoomOut, FileText, Maximize2, Minimize2, Edit3, X, Eye, EyeOff, Sparkles, Loader2, Wallet, Landmark, Info } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Modality, Type } from '@google/genai';

function App() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [month, setMonth] = useState(MONTHS[new Date().getMonth()]);
  const [year, setYear] = useState(new Date().getFullYear().toString());
  const [previousBalance, setPreviousBalance] = useState<string>('0.00');
  const [zoom, setZoom] = useState(0.55);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isFullPreview, setIsFullPreview] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  // Voice State
  const [isListening, setIsListening] = useState(false);
  const sessionRef = useRef<any>(null);

  const previewContainerRef = useRef<HTMLDivElement>(null);
  const A4_WIDTH_PX = 794;

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem('idm_report_data');
    if (saved) {
      const data = JSON.parse(saved);
      setTransactions(data.transactions || []);
      setMonth(data.month || MONTHS[new Date().getMonth()]);
      setYear(data.year || new Date().getFullYear().toString());
      setPreviousBalance(data.previousBalance?.toString() || '0.00');
    }

    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  useEffect(() => {
    localStorage.setItem('idm_report_data', JSON.stringify({ transactions, month, year, previousBalance }));
  }, [transactions, month, year, previousBalance]);

  // --- DERIVED STATE: VALORES PARA SEDE ---
  const sedeSummary = useMemo(() => {
    let dizimoSede = 0;
    let repasseSemid = 0;
    let parcelasSede = 0;

    transactions.forEach(t => {
      const desc = t.description.toLowerCase();

      // 1. Dízimo da Sede
      if (desc.includes("dízimo da sede") && t.type === TransactionType.EXIT) {
        dizimoSede += t.value;
      }

      // 2. Repasse SEMID
      if (desc.includes("repasse semid") && t.type === TransactionType.EXIT) {
        repasseSemid += t.value;
      }

      // 3. Parcelas (detecta 1 de 5, parcela, 1/3, etc)
      const isInstallment = desc.includes("parcela") || /\d+\s*de\s*\d+/.test(desc) || /\d+\/\d+/.test(desc);
      if (isInstallment && t.type === TransactionType.EXIT) {
        parcelasSede += t.value;
      }
    });

    return {
      dizimoSede,
      repasseSemid,
      parcelasSede,
      total: dizimoSede + repasseSemid + parcelasSede
    };
  }, [transactions]);

  const handleFitWidth = () => {
    if (previewContainerRef.current) {
      const containerWidth = previewContainerRef.current.clientWidth;
      const newZoom = (containerWidth - 40) / A4_WIDTH_PX; 
      setZoom(Math.max(newZoom, 0.2));
    }
  };

  useEffect(() => {
    setTimeout(handleFitWidth, 200);
    window.addEventListener('resize', handleFitWidth);
    return () => window.removeEventListener('resize', handleFitWidth);
  }, [isFullPreview]);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(e => console.error(e));
    } else {
      document.exitFullscreen();
    }
  };

  // --- BUSINESS LOGIC ---

  const addTransactions = (newItems: any[]) => {
    setTransactions(prev => {
      let updated = [...prev];
      newItems.forEach(data => {
        const normalizedDesc = data.description.trim();

        // Auto-detect installments to force EXIT type
        const isInstallment = normalizedDesc.toLowerCase().includes("parcela") || 
                             /\d+\s*de\s*\d+/.test(normalizedDesc.toLowerCase()) || 
                             /\d+\/\d+/.test(normalizedDesc.toLowerCase());

        const finalType = isInstallment ? TransactionType.EXIT : data.type;

        const existingIndex = updated.findIndex(t => t.day === data.day && t.description.toLowerCase() === normalizedDesc.toLowerCase() && t.type === finalType);

        if (existingIndex >= 0) {
          updated[existingIndex] = { ...updated[existingIndex], value: updated[existingIndex].value + data.value };
        } else {
          updated.push({ id: uuidv4(), day: data.day, description: normalizedDesc, value: data.value, type: finalType });
        }

        // Auto Repasse SEMID logic
        if (data.type === TransactionType.ENTRY && (normalizedDesc.toLowerCase().includes("ceia"))) {
           const repasse = { id: uuidv4(), day: data.day, description: "REPASSE SEMID", value: data.value, type: TransactionType.EXIT };
           updated.push(repasse);
        }
      });
      return updated;
    });
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const calculateDizimoSede = () => {
    const totalEntries = transactions.filter(t => t.type === TransactionType.ENTRY).reduce((acc, t) => acc + t.value, 0);
    const value = parseFloat((totalEntries * 0.10).toFixed(2));
    if (value > 0) addTransactions([{ day: new Date().getDate().toString().padStart(2, '0'), description: "Dízimo da Sede (10%)", value, type: TransactionType.EXIT }]);
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('report-content');
    if (element) {
       setIsGeneratingPdf(true);
       // @ts-ignore
       window.html2pdf().set({
         margin: 0, filename: `Relatorio_${month}_${year}.pdf`,
         image: { type: 'jpeg', quality: 0.98 },
         html2canvas: { scale: 2, scrollY: 0, useCORS: true },
         jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
       }).from(element).save().then(() => setIsGeneratingPdf(false)).catch(() => setIsGeneratingPdf(false));
    }
  };

  // --- VOICE COMMANDS (LIVE API) ---

  const startVoiceSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const controlFunctions = [
      {
        name: 'add_entry',
        description: 'Adiciona uma nova transação (entrada ou saída). Use para lançamentos do dia a dia.',
        parameters: {
          type: Type.OBJECT,
          properties: {
            day: { type: Type.STRING },
            description: { type: Type.STRING },
            value: { type: Type.NUMBER },
            type: { type: Type.STRING, enum: ['ENTRADA', 'SAIDA'] }
          },
          required: ['description', 'value', 'type']
        }
      },
      {
        name: 'update_report_config',
        description: 'Atualiza o saldo anterior, o mês ou o ano do relatório.',
        parameters: {
          type: Type.OBJECT,
          properties: {
            previousBalance: { type: Type.NUMBER, description: 'O novo valor do saldo anterior' },
            month: { type: Type.STRING, description: 'O nome do mês' },
            year: { type: Type.STRING, description: 'O ano com 4 dígitos' }
          }
        }
      },
      { name: 'delete_last', description: 'Remove o último lançamento feito.' },
      { name: 'download_report', description: 'Gera e baixa o PDF do relatório.' },
      { name: 'calculate_dizimo', description: 'Calcula e adiciona o dízimo da sede de 10%.' },
      { name: 'full_preview', description: 'Entra ou sai do modo de visualização em tela cheia do PDF.' },
      { name: 'set_zoom', description: 'Ajusta o zoom da visualização.', parameters: { type: Type.OBJECT, properties: { level: { type: Type.NUMBER } } } }
    ];

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new AudioContext({ sampleRate: 16000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: controlFunctions }],
          systemInstruction: `Você é um assistente de tesouraria da IDM. 
          1. Se o usuário falar sobre dinheiro que sobrou, saldo que veio do mês passado ou saldo anterior, use 'update_report_config' com o campo 'previousBalance'.
          2. Se o usuário quiser mudar o mês ou ano, use 'update_report_config'.
          3. Para lançamentos normais, use 'add_entry'.
          4. Se o usuário mencionar parcelas ou compras parceladas, entenda que é uma SAIDA.`
        },
        callbacks: {
          onopen: () => {
            const source = audioContext.createMediaStreamSource(stream);
            const processor = audioContext.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(processor);
            processor.connect(audioContext.destination);
            setIsListening(true);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                if (fc.name === 'add_entry') addTransactions([{ ...fc.args, day: fc.args.day || new Date().getDate().toString() }]);
                if (fc.name === 'update_report_config') {
                  if (fc.args.previousBalance !== undefined) setPreviousBalance(fc.args.previousBalance.toString());
                  if (fc.args.month) {
                    const matchedMonth = MONTHS.find(m => m.toLowerCase().includes(fc.args.month.toLowerCase()));
                    if (matchedMonth) setMonth(matchedMonth);
                  }
                  if (fc.args.year) setYear(fc.args.year.toString());
                }
                if (fc.name === 'download_report') handleDownloadPDF();
                if (fc.name === 'calculate_dizimo') calculateDizimoSede();
                if (fc.name === 'full_preview') setIsFullPreview(prev => !prev);
                if (fc.name === 'delete_last') setTransactions(prev => prev.slice(0, -1));
                if (fc.name === 'set_zoom') setZoom(fc.args.level || 0.6);

                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          },
          onclose: () => setIsListening(false),
          onerror: () => setIsListening(false)
        }
      });
      sessionRef.current = { stop: () => { audioContext.close(); stream.getTracks().forEach(t => t.stop()); } };
    } catch (e) {
      console.error(e);
      alert("Erro ao acessar microfone.");
    }
  };

  const toggleVoice = () => {
    if (isListening) {
      sessionRef.current?.stop();
      setIsListening(false);
    } else {
      startVoiceSession();
    }
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col lg:flex-row bg-slate-950 text-slate-100 overflow-hidden font-sans">

      {/* SIDEBAR */}
      {!isFullPreview && (
        <div className="w-full lg:w-[440px] bg-slate-900 border-r border-slate-800 flex flex-col h-[65%] lg:h-full z-30 shadow-2xl">

          {/* Header Sidebar */}
          <div className="p-4 bg-slate-950 border-b border-slate-800 flex items-center justify-between shrink-0">
            <h1 className="text-lg font-bold text-yellow-500 flex items-center gap-2">
              <Calculator size={20} /> Financeiro IDM
            </h1>
            <div className="flex gap-2">
               <button onClick={toggleFullScreen} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400" title="Tela Cheia do Navegador">
                 {isFullscreen ? <Minimize2 size={18} /> : <Maximize2 size={18} />}
               </button>
               <button onClick={() => setIsFullPreview(true)} className="p-2 bg-blue-600/20 text-blue-400 hover:bg-blue-600/30 rounded-lg lg:hidden" title="Ver PDF">
                 <Eye size={18} />
               </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">

            {/* PAINEL DE REMESSA PARA SEDE (EXCLUSIVO APP) */}
            <div className="bg-gradient-to-br from-amber-600/20 to-amber-900/40 border border-amber-500/30 rounded-2xl p-4 shadow-xl">
               <div className="flex items-center justify-between mb-3">
                  <h3 className="text-amber-400 font-bold text-xs uppercase tracking-widest flex items-center gap-2">
                    <Landmark size={14} /> Valor a Entregar à Sede
                  </h3>
                  <div className="group relative">
                    <Info size={12} className="text-amber-500/50 cursor-help" />
                    <div className="absolute right-0 bottom-full mb-2 w-48 p-2 bg-slate-950 border border-slate-800 rounded-lg text-[10px] text-slate-400 hidden group-hover:block z-50">
                      Soma de Dízimo da Sede, Repasses SEMID e Parcelas de Compras. Estes valores não somam no Saldo do Relatório.
                    </div>
                  </div>
               </div>

               <div className="grid grid-cols-2 gap-2 mb-3">
                  <div className="bg-black/20 p-2 rounded-lg">
                    <span className="text-[9px] uppercase text-amber-500/70 block">Dízimo Sede</span>
                    <span className="text-sm font-mono font-bold text-amber-200">R$ {sedeSummary.dizimoSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </div>
                  <div className="bg-black/20 p-2 rounded-lg">
                    <span className="text-[9px] uppercase text-amber-500/70 block">Repasse SEMID</span>
                    <span className="text-sm font-mono font-bold text-amber-200">R$ {sedeSummary.repasseSemid.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </div>
                  <div className="bg-black/20 p-2 rounded-lg col-span-2 flex justify-between items-center">
                    <span className="text-[9px] uppercase text-amber-500/70">Parcelas / Compras</span>
                    <span className="text-sm font-mono font-bold text-amber-200">R$ {sedeSummary.parcelasSede.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </div>
               </div>

               <div className="bg-amber-500/20 p-3 rounded-xl border border-amber-500/30 flex justify-between items-center">
                  <span className="text-xs font-black text-amber-400 uppercase">Total Geral Sede</span>
                  <span className="text-xl font-mono font-black text-amber-400">R$ {sedeSummary.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
               </div>
            </div>

            {/* Configuração do Relatório */}
            <div className="grid grid-cols-2 gap-3 bg-slate-800/40 p-3 rounded-2xl border border-slate-800">
              <div>
                <label className="text-[10px] uppercase text-slate-500 font-bold block mb-1 ml-1">Período</label>
                <select value={month} onChange={e => setMonth(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-xl p-2 text-xs outline-none focus:border-yellow-500 transition-colors">
                  {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                </select>
              </div>
              <div>
                <label className="text-[10px] uppercase text-slate-500 font-bold block mb-1 ml-1">Ano</label>
                <input type="text" value={year} onChange={e => setYear(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-xl p-2 text-xs outline-none focus:border-yellow-500 transition-colors" />
              </div>
              <div className="col-span-2">
                <label className="text-[10px] uppercase text-slate-500 font-bold block mb-1 ml-1">Saldo Anterior (R$)</label>
                <div className="relative">
                  <Wallet size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-600" />
                  <input type="number" step="0.01" value={previousBalance} onChange={e => setPreviousBalance(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-xl p-2 pl-9 text-sm font-mono outline-none focus:border-yellow-500 transition-colors" />
                </div>
              </div>
            </div>

            <InputBar onAdd={(item) => addTransactions([item])} isListening={isListening} onToggleVoice={toggleVoice} />

            <div className="flex flex-col gap-2">
               <button onClick={calculateDizimoSede} className="w-full py-3 bg-purple-600/10 hover:bg-purple-600/20 text-purple-400 border border-purple-600/30 rounded-xl text-xs font-black transition-all flex items-center justify-center gap-2 uppercase tracking-tighter">
                 <Sparkles size={16}/> Lançar Dízimo Sede Automático (10%)
               </button>
            </div>

            {/* Histórico de Lançamentos */}
            <div className="space-y-2">
              <div className="flex justify-between items-center px-1">
                <h3 className="text-[10px] uppercase font-bold text-slate-500 tracking-widest">Lançamentos Recentes</h3>
                <span className="bg-slate-800 px-2 py-0.5 rounded-full text-[10px] text-slate-400 font-bold">{transactions.length}</span>
              </div>
              <div className="space-y-2">
                {transactions.slice().reverse().map(t => {
                  const isInstallment = t.description.toLowerCase().includes("parcela") || /\d+\s*de\s*\d+/.test(t.description.toLowerCase());
                  return (
                    <div key={t.id} className={`group bg-slate-800/30 border ${isInstallment ? 'border-amber-900/30' : 'border-slate-800'} hover:border-slate-600 p-3 rounded-2xl flex items-center justify-between transition-all`}>
                      <div className="flex flex-col">
                        <div className="flex items-center gap-2">
                          <span className={`w-1.5 h-1.5 rounded-full ${t.type === TransactionType.ENTRY ? 'bg-green-500' : 'bg-red-500'}`}></span>
                          <span className="text-[10px] font-bold text-slate-500 uppercase">DIA {t.day}</span>
                          {isInstallment && <span className="bg-amber-500/20 text-amber-500 text-[8px] px-1 rounded font-black">PARCELA</span>}
                        </div>
                        <span className="text-sm font-semibold text-slate-200 uppercase truncate max-w-[200px]">{t.description}</span>
                      </div>
                      <div className="flex flex-col items-end gap-1">
                        <span className={`font-mono font-bold text-base ${t.type === TransactionType.ENTRY ? 'text-green-400' : 'text-red-400'}`}>
                          {t.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                        </span>
                        <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => setEditingTransaction(t)} className="p-2 hover:bg-slate-700 rounded-lg text-blue-400 transition-colors"><Edit3 size={14} /></button>
                          <button onClick={() => deleteTransaction(t.id)} className="p-2 hover:bg-red-900/40 rounded-lg text-red-500 transition-colors"><Trash2 size={14} /></button>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          <div className="p-4 bg-slate-950 border-t border-slate-800 shrink-0">
            <button onClick={handleDownloadPDF} disabled={isGeneratingPdf} className="w-full bg-yellow-500 hover:bg-yellow-600 text-slate-950 font-black py-4 rounded-2xl flex items-center justify-center gap-3 shadow-2xl shadow-yellow-500/10 disabled:opacity-50 transition-all uppercase tracking-tight text-base">
              {isGeneratingPdf ? <Loader2 className="animate-spin" /> : <Download size={24} />} BAIXAR PDF DO RELATÓRIO
            </button>
          </div>
        </div>
      )}

      {/* PREVIEW AREA */}
      <div className={`flex-1 flex flex-col bg-slate-800 relative transition-all duration-500 ${isFullPreview ? 'w-full h-full' : 'h-[35%] lg:h-full'}`}>

        {/* Full Preview Controls Overlay */}
        <div className="absolute top-6 right-6 z-40 flex gap-3 no-print">
           {isFullPreview && (
             <button onClick={() => setIsFullPreview(false)} className="bg-red-600 hover:bg-red-700 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 font-black uppercase text-xs transition-all hover:scale-105 active:scale-95">
               <X size={20} /> Fechar Prévia
             </button>
           )}
           {!isFullPreview && (
              <button onClick={() => setIsFullPreview(true)} className="hidden lg:flex bg-slate-900/90 backdrop-blur hover:bg-slate-900 text-white px-5 py-3 rounded-full shadow-2xl items-center gap-2 font-black uppercase text-xs border border-slate-700 transition-all hover:scale-105">
                <Maximize2 size={18} /> Ver em Tela Cheia
              </button>
           )}
        </div>

        {/* Status Bar Zoom */}
        <div className="h-12 bg-slate-950 border-b border-slate-800 flex items-center justify-between px-6 shrink-0 no-print">
           <div className="flex items-center gap-3">
             <div className="bg-blue-600 w-2 h-2 rounded-full animate-pulse"></div>
             <span className="text-[10px] font-black text-slate-400 tracking-widest uppercase">Visualizador de Relatório A4</span>
             {isFullPreview && <span className="bg-blue-500/20 text-blue-400 px-3 py-1 rounded-full text-[10px] font-black border border-blue-500/30">MODO FOCO ATIVADO</span>}
           </div>
           <div className="flex items-center gap-4 bg-slate-900 rounded-xl p-1 px-3 border border-slate-800">
             <button onClick={() => setZoom(z => Math.max(0.2, z-0.1))} className="p-1.5 hover:text-white transition-colors"><ZoomOut size={18}/></button>
             <span className="text-xs font-mono font-bold w-12 text-center text-slate-300">{Math.round(zoom*100)}%</span>
             <button onClick={() => setZoom(z => Math.min(2, z+0.1))} className="p-1.5 hover:text-white transition-colors"><ZoomIn size={18}/></button>
             <div className="w-px h-4 bg-slate-700 mx-1"></div>
             <button onClick={handleFitWidth} className="p-1.5 hover:text-blue-400 transition-colors" title="Ajustar à Largura"><Maximize2 size={16}/></button>
           </div>
        </div>

        {/* The "Paper" Container */}
        <div ref={previewContainerRef} className="flex-1 overflow-auto p-4 lg:p-12 flex justify-center bg-slate-800 custom-scrollbar scroll-smooth">
           <div className="origin-top transition-transform duration-300 shadow-[0_40px_100px_-20px_rgba(0,0,0,0.8)] rounded-sm overflow-hidden" style={{ transform: `scale(${zoom})` }}>
              <div id="report-content" className="bg-white">
                <PaperReport transactions={transactions} header={{ month, year, previousBalance: parseFloat(previousBalance || '0') }} />
              </div>
           </div>
        </div>
      </div>

      {/* EDIT MODAL */}
      {editingTransaction && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-lg rounded-3xl shadow-3xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-5 bg-slate-800 border-b border-slate-700 flex justify-between items-center">
              <h3 className="font-black text-lg uppercase tracking-tight flex items-center gap-3">
                <div className="p-2 bg-blue-600/20 text-blue-400 rounded-xl"><Edit3 size={20}/></div>
                Editar Lançamento
              </h3>
              <button onClick={() => setEditingTransaction(null)} className="p-2 hover:bg-slate-700 rounded-full transition-colors"><X size={24}/></button>
            </div>
            <div className="p-8 space-y-6">
              <div className="grid grid-cols-4 gap-4">
                <div className="col-span-1">
                  <label className="text-[10px] uppercase font-black text-slate-500 block mb-2">Dia</label>
                  <input type="text" value={editingTransaction.day} onChange={e => setEditingTransaction({...editingTransaction, day: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-3 text-base outline-none focus:border-blue-500 font-bold transition-all" />
                </div>
                <div className="col-span-3">
                  <label className="text-[10px] uppercase font-black text-slate-500 block mb-2">Descrição / Motivo</label>
                  <input type="text" value={editingTransaction.description} onChange={e => setEditingTransaction({...editingTransaction, description: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-3 text-base outline-none focus:border-blue-500 font-bold uppercase transition-all" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-[10px] uppercase font-black text-slate-500 block mb-2">Valor (R$)</label>
                  <input type="number" step="0.01" value={editingTransaction.value} onChange={e => setEditingTransaction({...editingTransaction, value: parseFloat(e.target.value) || 0})} className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-3 text-lg outline-none focus:border-blue-500 font-mono font-black transition-all" />
                </div>
                <div>
                  <label className="text-[10px] uppercase font-black text-slate-500 block mb-2">Categoria</label>
                  <select value={editingTransaction.type} onChange={e => setEditingTransaction({...editingTransaction, type: e.target.value as TransactionType})} className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-3 text-base outline-none focus:border-blue-500 font-bold transition-all appearance-none">
                    <option value={TransactionType.ENTRY}>ENTRADA</option>
                    <option value={TransactionType.EXIT}>SAÍDA</option>
                  </select>
                </div>
              </div>
              <div className="pt-6 flex gap-4">
                <button onClick={() => setEditingTransaction(null)} className="flex-1 py-4 bg-slate-800 hover:bg-slate-700 rounded-2xl font-black transition-all uppercase text-sm tracking-widest border border-slate-700">CANCELAR</button>
                <button onClick={() => updateTransaction(editingTransaction)} className="flex-1 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-black transition-all shadow-xl shadow-blue-500/20 uppercase text-sm tracking-widest">SALVAR ALTERAÇÕES</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
